# signoff_package.py — generate business sign-off document from UAT results
import json
from dataclasses import dataclass, field
from pathlib import Path

@dataclass
class CriterionVerdict:
    criterion_id: str
    verdict: str               # PASS | FAIL | WAIVER_REQUESTED
    evidence_summary: str      # one paragraph readable by non-engineers
    supporting_data: dict      # raw numbers for the appendix
    waiver_request: str = ""   # filled if WAIVER_REQUESTED

@dataclass
class SignOffPackage:
    feature: str
    release: str
    prepared_by: str
    verdicts: list[CriterionVerdict] = field(default_factory=list)

    @property
    def blocking_failures(self) -> list[str]:
        return [
            v.criterion_id for v in self.verdicts
            if v.verdict == "FAIL"
        ]

    @property
    def overall_recommendation(self) -> str:
        if self.blocking_failures:
            return "HOLD — blocking failures present"
        waiver_requests = [v for v in self.verdicts if v.verdict == "WAIVER_REQUESTED"]
        if waiver_requests:
            return "CONDITIONAL — requires waiver approval"
        return "APPROVE"

    def to_markdown(self) -> str:
        lines = [
            f"# Business Sign-Off Package",
            f"**Feature:** {self.feature}",
            f"**Release:** {self.release}",
            f"**Prepared by:** {self.prepared_by}",
            f"**Overall Recommendation:** {self.overall_recommendation}",
            "",
            "---",
            "",
            "## Acceptance Criteria Results",
        ]
        for v in self.verdicts:
            icon = {"PASS": "✓", "FAIL": "✗", "WAIVER_REQUESTED": "⚠"}[v.verdict]
            lines += [
                f"### [{icon} {v.verdict}] {v.criterion_id}",
                f"**Evidence:** {v.evidence_summary}",
            ]
            if v.waiver_request:
                lines += [f"**Waiver Request:** {v.waiver_request}"]
            lines.append("")
        if self.blocking_failures:
            lines += [
                "---",
                "## Blocking Failures — Release on Hold",
                "The following criteria failed and cannot be waived. Release cannot proceed until resolved:",
            ]
            for cid in self.blocking_failures:
                lines.append(f"- {cid}")
        return "\n".join(lines)

# waiver.py — conditional approval waiver record
from dataclasses import dataclass
from datetime import date

@dataclass
class Waiver:
    waiver_id: str
    criterion_id: str
    criterion_title: str
    failure_description: str     # what failed and by how much
    business_justification: str  # why it is acceptable to ship anyway
    affected_users: str          # estimate of impact scope
    risk_acceptance: str         # the risk being accepted in plain language
    mitigations: list[str]       # what will reduce the risk post-launch
    monitoring: str              # what will be monitored to catch the risk manifesting
    rollback_trigger: str        # the condition that triggers rollback
    approved_by: str             # named approver with authority
    approval_date: date
    review_date: date            # when the waiver will be re-evaluated

    def to_markdown(self) -> str:
        mitigations_md = "\n".join(f"  - {m}" for m in self.mitigations)
        return f"""## Waiver {self.waiver_id}: {self.criterion_title}

**Criterion failed:** {self.failure_description}
**Justification:** {self.business_justification}
**Affected users:** {self.affected_users}
**Risk accepted:** {self.risk_acceptance}

**Mitigations in place:**
{mitigations_md}

**Post-launch monitoring:** {self.monitoring}
**Rollback trigger:** {self.rollback_trigger}

**Approved by:** {self.approved_by}
**Approval date:** {self.approval_date}
**Review date:** {self.review_date}
"""

# Example waiver
latency_waiver = Waiver(
    waiver_id="WVR-2024-001",
    criterion_id="bc-04",
    criterion_title="Response latency",
    failure_description="p95 latency measured at 3.4 seconds, exceeding the 3.0s threshold, under 500-user load. p50 latency is 1.8 seconds.",
    business_justification="Peak load of 500 concurrent users occurs for at most 2 hours per day during business hours. Initial rollout is limited to 10% of traffic, so actual concurrent load will be 50 users — well within the 2.5s p95 threshold seen in testing at lower load.",
    affected_users="10% of support chat users during peak hours (~500 users/day initially)",
    risk_acceptance="Some users may experience slightly longer wait times during high-load periods. Estimated to affect <5% of sessions based on load distribution.",
    mitigations=[
        "Release limited to 10% rollout with feature flag",
        "Response streaming enabled to reduce perceived latency",
        "Auto-scaling policy tuned to reduce latency under load",
    ],
    monitoring="Datadog dashboard: p95 latency by hour. Alert if p95 exceeds 4.0s for 3 consecutive minutes.",
    rollback_trigger="p95 latency exceeds 5.0s for 5 consecutive minutes OR customer complaints about latency increase by 20% vs baseline.",
    approved_by="VP Engineering (Jane Smith)",
    approval_date=date(2024, 11, 15),
    review_date=date(2024, 12, 15),
)
